; SID Music Player - Architecture Overview
;
;                      +---------------------+
;                      | Entry: LDX #$02     |
;                      | (voice 2, 1, 0)     |
;                      +---------------------+
;                                |
;                      +---------------------+
;                      | Save $FB/$FC        |
;                      +---------------------+
;                                |
;                      +---------------------+
;                      | Voice active?       |
;                      | voice_active,x != 0 |
;                      +-----+---------------+
;                       Yes  |           No \
;                            |              +---> next_voice
;                      +-----v---------------+      (DEX, loop
;                      | Speed counter       |       or RTS)
;                      | voice_speed_ctr != 0|
;                      +-----+--------+------+
;                       == 0 |        | != 0
;                            |        +---> Sustain: dec ctr,
;                            |              check release tick
;                      +-----v---------------+
;                      | Fetch next command   |
;                      | from pattern data    |
;                      +-----+---------------+
;                            |
;              +-------------+-------------+
;              |             |             |
;         +----v----+   +----v----+   +----v--------+
;         | Note    |   | Rest    |   | Control     |
;         | $01-$7D |   | $00     |   | $80+        |
;         | gate on |   | gate off|   +------+------+
;         +----+----+   +----+----+          |
;              |             |     +---------+---------+
;              |             |     |         |         |
;              +------+------+ +--v---+ +---v---+ +---v------+
;                     |         |Speed | |Instr. | |Effects   |
;                     |         |$80   | |$A0    | |$C0+      |
;                     |         +------+ +-------+ +---+------+
;                     |                                 |
;                     |              +------+------+----+----+
;                     |              |      |      |         |
;                     |          +---v--+ +-v---+ +v------+ +v-------+
;                     |          |Vibr. | |Porta| |Release| |Arpeggio|
;                     |          +------+ +-----+ +-------+ +--------+
;                     |
;               +-----v--------------+
;               | Calc frequency     |
;               | from freq table    |
;               | + apply effects    |
;               +-----+--------------+
;                     |
;               +-----v--------------+
;               | Write SID regs     |
;               | $D400-$D418        |
;               | Freq, PW, Filter,  |
;               | Control, ADSR      |
;               +-----+--------------+
;                     |
;               +-----v--------------+
;               | next_voice: DEX    |
;               | loop or RTS        |
;               +--------------------+
; -=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=
sid_init            jmp sid_init_voices  ; x-ref: $2e75
