voice_freq_lo       .byte $a9, $b5, $00  ; x-ref: $14c4, $14fe, $154d, $1554, $15d4, ...
voice_freq_hi       .byte $03, $1c, $00, $fc, $3e ; x-ref: $14bf, $1506, $1557, $155d, $15de, ...
