; =-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-
; Advances a sine wave phase index and splits the corresponding table value
; into a fine scroll value (for VIC-II $D016) and a coarse character offset
; (for screen tile positioning). Used by all three tube bands.
;
; Inputs:  X = current sine phase index (0-159, maintained via self-mod by caller)
; Outputs: A = $D016 value (fine scroll 0-7 inverted | multicolor bit),
;          Y = coarse character offset (0-31),
;          X = updated phase index
; Side Effects: None (pure computation)
; =-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-
sine_scroller_update
                    inx                  ; Advance sine phase ; x-ref: $0e0a, $0e2a, $0e4a
                    cpx #$a0             ; Table has 160 entries
                    bne b2207
                    ldx #$00             ; Wrap to 0 at end of table
b2207               lda sine_table,x     ; Read 8-bit sine value (0-255) ; x-ref: $2203
                    pha                  ; Save full value for fine scroll extraction
                    and #$f8             ; Keep bits 7-3 (coarse part)
                    lsr a
                    lsr a
                    lsr a
                    tay                  ; Y = coarse character offset
                    pla                  ; Restore full sine value
                    and #$07             ; Keep bits 2-0 (fine scroll 0-7)
                    eor #$07             ; Invert: VIC scrolls opposite direction
                    ora #$10             ; Set bit 4 = multicolor mode for $D016
                    rts
