; =-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-
; Main entry point, initialization, and execution loop of the demo.
; Sets up VIC-II, clears screen, initializes tables, hooks raster IRQ,
; and runs the main loop with scroller and effect updates.
;
; Inputs:  None
; Outputs: None
; Side Effects: Modifies VIC-II, SID, Screen RAM, Color RAM, and hooks IRQ.
; =-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-=-
main_init           sei                  ; Disable interrupts for setup
                    lda #$00
                    sta $d011            ; Blank screen during init; VIC Control Register 1
                    sta $d020            ; Border Color
                    lda #$08
                    sta $d021            ; Background Color 0
                    sta a0286
                    jsr eE544            ; Clear screen using KERNAL
                    lda #<pFEC1          ; Disable NMI (Restore key)
                    sta a0318            ; NMI
                    ldx #$a0
b2E1B               lda f0CC7,x          ; x-ref: $2e30
                    sta f0477,x
                    lda f0D67,x
                    sta f0517,x
                    lda #$00
                    sta f062F,x
                    sta a06CF,x
                    dex
                    bne b2E1B
                    ldx #$27
b2E34               lda #$00             ; x-ref: $2e5d
                    sta f0450,x
                    sta f05B8,x
                    lda #$fe
                    sta f0630,x
                    sta f0748,x
                    lda #$08
                    sta fDA30,x
                    sta fDB48,x
                    lda #$ff
                    sta f0658,x
                    sta f0720,x
                    lda #$09
                    sta fDA58,x
                    sta fDB20,x
                    dex
                    bpl b2E34
                    lda #$01             ; Enable raster interrupt
                    sta $d01a            ; VIC Interrupt Mask Register (IMR)
                    sta $dc0d            ; CIA1: CIA Interrupt Control Register
                    lda $dc0d            ; CIA1: CIA Interrupt Control Register
                    lda #$f8
                    ldx #<irq_hanlder_f8
                    ldy #>irq_hanlder_f8
                    jsr set_next_irq_state
                    lda #$00
                    jsr sid_init         ; Initialize SID music
                    jsr update_scroller_and_tubes
                    cli                  ; Enable interrupts
                    ldx #$c1
b2E7E               jsr wait_frame_or_exit ; x-ref: $2e82
                    dex
                    bne b2E7E
                    lda #$2c             ; Enable logo/effect via self-mod
                    sta a2272
                    ldx #$c1
b2E8B               jsr wait_frame_or_exit ; x-ref: $2e8f
                    dex
                    bne b2E8B
main_loop           jsr wait_frame_or_exit ; x-ref: $2e97
                    jsr update_scroller_and_tubes
                    jmp main_loop
set_next_irq_state  sty a0315            ; x-ref: $23cb, $2e70, $2ed3; IRQ
                    stx a0314            ; IRQ
                    sta $d012            ; Raster Position
                    rts
a2EA5 =*+$01
wait_frame_or_exit  lda #$00             ; x-ref: $2e7e, $2e8b, $2e91, $2ea6
                    beq wait_frame_or_exit
                    dec a2EA5
                    lda $dc01            ; CIA1: Data Port Register B
                    cmp #$ef
                    bne b2EB5
                    jmp handle_exit
b2EB5               rts                  ; x-ref: $2eb0
handle_exit         pla                  ; x-ref: $2eb2
                    pla
                    sei
                    lda #$00
                    sta $d011            ; VIC Control Register 1
                    sta $d021            ; Background Color 0
                    sta aC6
                    ldx #$1c
b2EC5               sta $d400,x          ; x-ref: $2ec9; Voice 1: Frequency Control - Low-Byte
                    dex
                    bpl b2EC5
                    jsr eE544            ; Clear screen
                    lda #<pEA31          ; set default IRQ vector
                    tax
                    ldy #>pEA31
                    jsr set_next_irq_state
                    ldx #$1f
                    jsr eE5AA            ; set VIC registers to default ones
                    jsr ROM_IOINITj      ; $FDA3 (jmp) - initialize CIA & IRQ
                    sei
                    ldx #$27
b2EE1               lda #$08             ; x-ref: $2eed
                    sta fD9E0,x          ; screen color
                    lda txt_credits_exit,x
                    sta f05E0,x
                    dex
                    bpl b2EE1
                    ldx #$34
                    stx a01
b2EF3               lda cleanup_reloc_0340,x ; x-ref: $2efa
                    sta f0340,x
                    dex
                    bpl b2EF3
                    jmp f0340
                    .byte $00
                    .encode
                    .enc "screen"
scroller_txt        .text "WELCOME TO AN OLDSCHOOL INTRO BY DIDI CA" ; x-ref: $0ea5, $0eaa, $0eaf
                    .text "LLED ""MOVING TUBES"" FOR THE 16K CATEGORY"
                    .text " OF ICC 2026! IT USES A LOGO BY AGD, TUB"
                    .text "ES AND 4X4 CHARSET BY DMD AND COOL OLD M"
                    .text "USIC BY DEEK. ALL WAS CODED ON FEBRUARY "
                    .text "11TH IN 2026, AFTER SOME DATA COLLECTING"
                    .text " THE DAY BEFORE. ENJOY!                 "
                    .text "   "
